<app-header></app-header>
<section>
  <form>
    <!-- Filtro de níveis (múltiplos) -->
    <div *ngFor="let levelOption of levels">
      <label>
        <input 
          type="checkbox" 
          [value]="levelOption"
          (change)="updateFilter('level', levelOption, $event.target.checked)" />
        Nível {{ levelOption }}
      </label>
    </div>

    <!-- Filtro de escola (único) -->
    <div>
      <label for="school">Escola</label>
      <select id="school" (change)="updateFilter('school', $event.target.value)">
        <option value="">Selecione a Escola</option>
        <option *ngFor="let schoolOption of schools" [value]="schoolOption">{{ schoolOption }}</option>
      </select>
    </div>

    <!-- Filtro de classe (único) -->
    <div>
      <label for="class">Classe</label>
      <select id="class" (change)="updateFilter('class', $event.target.value)">
        <option value="">Selecione a Classe</option>
        <option *ngFor="let classOption of classes" [value]="classOption">{{ classOption }}</option>
      </select>
    </div>
  </form>

  <div *ngIf="loading">Carregando...</div>
  <div *ngIf="error">{{ error }}</div>

  <div *ngIf="!loading && !error">
    <div class="magics-container" *ngIf="magias.results.length > 0; else noResults">
      <div *ngFor="let magia of magias.results" class="item" (click)="goToDetail(magia.index)">
        <h3>{{ magia.name }}</h3>
      </div>
    </div>
    <ng-template #noResults>
      <p>Nenhuma magia encontrada com os filtros aplicados.</p>
    </ng-template>
  </div>
</section>
<app-footer></app-footer>
